class TweetCounts:

    def __init__(self):
        self.tweet_times = {}

    def recordTweet(self, tweetName: str, time: int) -> None:
        if tweetName not in self.tweet_times:
            self.tweet_times[tweetName] = []
        self.tweet_times[tweetName].append(time)

    def getTweetCountsPerFrequency(self, freq: str, tweetName: str, startTime: int, endTime: int) -> List[int]:
        if tweetName not in self.tweet_times:
            return []

        times = self.tweet_times[tweetName]
        chunk_size = 60 if freq == "minute" else 3600 if freq == "hour" else 86400
        start_chunk = startTime // chunk_size
        end_chunk = endTime // chunk_size
        result = []

        for chunk in range(start_chunk, end_chunk + 1):
            chunk_start = max(startTime, chunk * chunk_size)
            chunk_end = min(endTime, (chunk + 1) * chunk_size - 1)
            count = sum(1 for time in times if chunk_start <= time <= chunk_end)
            result.append(count)

        return result


